INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, "2030/01/01 14:59:59", 3.414, "2025/01/31 12:00:00", 1, 1, "カリン", 0.0, 1000001, 2, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", -416.5, 62, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, "2030/01/01 14:59:59", 3.099, "2025/01/31 12:00:00", 1, 1, "カリン", 0.0, 1000002, 2, "ミッションをクリアして、\n報酬をゲットしましょう！", -416.5, 62, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, "2030/01/01 14:59:59", 2.801, "2025/01/31 12:00:00", 1, 1, "カリン", 0.0, 1000003, 2, "受け取ることができる\n報酬があるようです\n確認してみてください", -416.5, 63, 3);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, "2030/01/01 14:59:59", 0.0, "2025/01/31 12:00:00", 2, 1, "カリン", 0.0, 1000004, 2, "報酬がもらえますよ！\nチェックしてみてください", -416.5, 63, 4);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, "2030/01/01 14:59:59", 2.12, "2025/01/31 12:00:00", 2, 1, "カリン", 0.0, 1000005, 1, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", -363.0, 64, 5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, "2030/01/01 14:59:59", 1.68, "2025/01/31 12:00:00", 1, 1, "カリン", 0.0, 1000006, 2, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", -363.0, 64, 6);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, "2030/01/01 14:59:59", 2.33, "2025/01/31 12:00:00", 2, 1, "カリン", 0.0, 1000007, 1, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", -363.0, 64, 7);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (133701, "2030/01/01 14:59:59", 5.18, "2025/01/31 12:00:00", 3, 10201, "ラビリスタ", -6.0, 1020101, 7, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", -285.0, 61, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (133901, "2030/01/01 14:59:59", 8.77, "2025/01/31 12:00:00", 1, 10201, "クリスティーナ", -2.0, 1020102, 2, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", -285.0, 61, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (133801, "2030/01/01 14:59:59", 15.5, "2025/01/31 12:00:00", 6, 10201, "ネネカ", 0.0, 1020103, 1, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", -285.0, 61, 301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (134301, "2030/01/01 14:59:59", 9.061, "2025/02/28 12:00:00", 2, 10202, "ランファ", 0.0, 1020201, 5, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", -285.0, 61, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (134401, "2030/01/01 14:59:59", 7.699, "2025/02/28 12:00:00", 1, 10202, "チカ", 0.0, 1020202, 2, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", -285.0, 61, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (134601, "2030/01/01 14:59:59", 8.595, "2025/03/31 12:00:00", 1, 10203, "アオイ", 0.0, 1020301, 2, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", -285.0, 61, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (134501, "2030/01/01 14:59:59", 7.758, "2025/03/31 12:00:00", 1, 10203, "クローチェ", 0.0, 1020302, 2, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", -285.0, 61, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (132302, "2030/01/01 14:59:59", 7.0, "2025/04/30 12:00:00", 2, 10204, "ルイズマリー", 0.0, 1020401, 6, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", -285.0, 61, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (132402, "2030/01/01 14:59:59", 7.904, "2025/04/30 12:00:00", 1, 10204, "イロハ", 0.0, 1020402, 2, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", -285.0, 61, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (132502, "2030/01/01 14:59:59", 8.487, "2025/04/30 12:00:00", 4, 10204, "ソノ", 0.0, 1020403, 2, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", -285.0, 61, 301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (134901, "2030/01/01 14:59:59", 8.763, "2025/05/31 12:00:00", 1, 10205, "カノン", 0.0, 1020502, 2, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", -285.0, 61, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (134801, "2030/01/01 14:59:59", 6.417, "2025/05/31 12:00:00", 1, 10205, "ツムギ", 0.0, 1020503, 3, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", -285.0, 61, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (135001, "2030/01/01 14:59:59", 10.335, "2025/06/30 12:00:00", 3, 10206, "エリス", 0.0, 1020601, 7, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", -285.0, 61, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (135101, "2030/01/01 14:59:59", 6.281, "2025/06/30 12:00:00", 2, 10206, "シェフィ", 0.0, 1020602, 4, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", -285.0, 61, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (135201, "2030/01/01 14:59:59", 12.244, "2025/06/30 12:00:00", 1, 10206, "プレシア", 0.0, 1020603, 2, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", -285.0, 61, 301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (135301, "2030/01/01 14:59:59", 6.339, "2025/07/31 12:00:00", 2, 10207, "クリア", 0.0, 1020701, 8, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", -285.0, 61, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (135401, "2030/01/01 14:59:59", 8.184, "2025/07/31 12:00:00", 7, 10207, "アネモネ", 0.0, 1020702, 9, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", -285.0, 61, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (129101, "2030/01/01 14:59:59", 3.906, "2025/08/31 12:00:00", 9, 10208, "アイラ", 0.0, 1020801, 2, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", -285.0, 61, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (129201, "2030/01/01 14:59:59", 14.465, "2025/08/31 12:00:00", 1, 10208, "シナツ", 0.0, 1020802, 2, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", -285.0, 61, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (100101, "2030/01/01 14:59:59", 8.662, "2025/08/31 12:00:00", 4, 10208, "ヒヨリ", 0.0, 1020803, 3, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", -285.0, 61, 301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (100301, "2030/01/01 14:59:59", 10.915, "2025/08/31 12:00:00", 1, 10208, "レイ", 0.0, 1020804, 3, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", -285.0, 61, 401);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (135802, "2030/01/01 14:59:59", 6.042, "2025/09/30 12:00:00", 1, 10209, "ユキノ", 0.0, 1020901, 7, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", -285.0, 61, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (135903, "2030/01/01 14:59:59", 9.402, "2025/09/30 12:00:00", 4, 10209, "サツキ", 0.0, 1020902, 1, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", -285.0, 61, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (136902, "2030/01/01 14:59:59", 8.16, "2025/09/30 12:00:00", 8, 10209, "ルルィ", 0.0, 1020903, 1, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", -285.0, 61, 301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (137401, "2030/01/01 14:59:59", 5.0, "2025/10/31 12:00:00", 3, 10210, "カスミ", 0.0, 1021001, 2, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", -285.0, 61, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (136001, "2030/01/01 14:59:59", 8.12, "2025/10/31 12:00:00", 4, 10210, "アラクネ", 0.0, 1021002, 1, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", -285.0, 61, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (136202, "2030/01/01 14:59:59", 6.386, "2025/10/31 12:00:00", 4, 10210, "ナーナ", 0.0, 1021003, 2, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", -285.0, 61, 301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (136402, "2030/01/01 14:59:59", 7.438, "2025/11/30 12:00:00", 3, 10211, "ユイ", 0.0, 1021101, 4, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", -285.0, 61, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (136302, "2030/01/01 14:59:59", 8.35, "2025/11/30 12:00:00", 1, 10211, "ミソラ", 0.0, 1021102, 5, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", -285.0, 61, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (136501, "2030/01/01 14:59:59", 5.0, "2025/12/31 12:00:00", 1, 10212, "シズル", 0.0, 1021201, 2, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", -285.0, 61, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (137902, "2030/01/01 14:59:59", 5.25, "2025/12/31 12:00:00", 1, 10212, "リノ", 0.0, 1021202, 2, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", -285.0, 61, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (106801, "2030/01/01 14:59:59", 7.5, "2025/12/31 12:00:00", 1, 10212, "ラビリスタ", 0.0, 1021203, 2, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", -285.0, 61, 301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (126501, "2030/01/01 14:59:59", 8.204, "2026/01/31 12:00:00", 1, 10213, "ライラエル", 0.0, 1021301, 2, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", -285.0, 61, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (129701, "2030/01/01 14:59:59", 7.176, "2026/01/31 12:00:00", 1, 10213, "ネフィ＝ネラ", 0.0, 1021302, 2, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", -285.0, 61, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (133101, "2030/01/01 14:59:59", 8.602, "2026/01/31 12:00:00", 1, 10213, "ヴァイオレット", 0.0, 1021303, 5, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", -285.0, 61, 301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (138101, "2030/01/01 14:59:59", 10.14, "2026/02/06 12:00:00", 1, 10213, "ライラエル", 0.0, 1021304, 3, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", -285.0, 61, 102);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (138201, "2030/01/01 14:59:59", 10.152, "2026/02/06 12:00:00", 1, 10213, "ネフィ＝ネラ", 0.0, 1021305, 7, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", -285.0, 61, 202);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (138001, "2030/01/01 14:59:59", 9.688, "2026/02/06 12:00:00", 4, 10213, "ヴァイオレット", 0.0, 1021306, 3, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", -285.0, 61, 302);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (138301, "2030/01/01 14:59:59", 5.928, "2026/02/12 12:00:00", 2, 10213, "ペコリーヌ", 0.0, 1021307, 1, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", -285.0, 61, 401);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (138702, "2030/01/01 14:59:59", 9.19, "2026/02/28 12:00:00", 4, 10214, "ワカナ", 0.0, 1021401, 2, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", -285.0, 61, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (138802, "2030/01/01 14:59:59", 8.724, "2026/02/28 12:00:00", 1, 10214, "シオリ", 0.0, 1021402, 3, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", -285.0, 61, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (138902, "2030/01/01 14:59:59", 7.758, "2026/03/31 12:00:00", 4, 10215, "グレイス", 0.0, 1021501, 1, "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", -285.0, 61, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (139002, "2030/01/01 14:59:59", 6.375, "2026/03/31 12:00:00", 6, 10215, "キョウカ", 0.0, 1021502, 4, "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", -285.0, 61, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (136902, "2030/01/01 14:59:59", 6.173, "2026/03/31 12:00:00", 6, 10215, "ルルィ", 0.0, 1021503, 1, "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", -285.0, 61, 301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (139202, "2030/01/01 14:59:59", 4.202, "2026/04/30 12:00:00", 6, 10216, "ミホ", 0.0, 1021601, 2, "違う世界に来ちゃうし、\n驚きの連続だけど…\nわたしも精いっぱい頑張ります！\nアストルムのみんなと一緒に！", -285.0, 61, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (139302, "2030/01/01 14:59:59", 2.842, "2026/04/30 12:00:00", 6, 10216, "マホ", 0.0, 1021602, 1, "想定外の事象が発生したな…だが\nいかなる苦境も切り抜けてみせる\nいつもの自分とは違う姿になっても\nわたしはわたし、西住流だ", -285.0, 61, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (139402, "2030/01/01 14:59:59", 4.598, "2026/04/30 12:00:00", 4, 10216, "エリカ", 0.0, 1021603, 1, "何でこんなことになっているのか\n全然わからないけど、迷ってる暇は\nないわ。黒森峰の次期隊長として、\n前進あるのみ！　これも戦車道よ！", -285.0, 61, 301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, "2030/01/01 14:59:59", 3.414, "2026/04/10 12:00:00", 1, 2, "カリン", 0.0, 2000001, 2, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", -416.5, 62, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, "2030/01/01 14:59:59", 3.099, "2026/04/10 12:00:00", 1, 2, "カリン", 0.0, 2000002, 2, "ミッションをクリアして、\n報酬をゲットしましょう！", -416.5, 62, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, "2030/01/01 14:59:59", 2.801, "2026/04/10 12:00:00", 1, 2, "カリン", 0.0, 2000003, 2, "受け取ることができる\n報酬があるようです\n確認してみてください", -416.5, 63, 3);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, "2030/01/01 14:59:59", 0.0, "2026/04/10 12:00:00", 2, 2, "カリン", 0.0, 2000004, 2, "報酬がもらえますよ！\nチェックしてみてください", -416.5, 63, 4);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, "2030/01/01 14:59:59", 2.12, "2026/04/10 12:00:00", 2, 2, "カリン", 0.0, 2000005, 1, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", -363.0, 64, 5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, "2030/01/01 14:59:59", 1.68, "2026/04/10 12:00:00", 1, 2, "カリン", 0.0, 2000006, 2, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", -363.0, 64, 6);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (190801, "2030/01/01 14:59:59", 2.33, "2026/04/10 12:00:00", 2, 2, "カリン", 0.0, 2000007, 1, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", -363.0, 64, 7);
